import os
import subprocess
from google.cloud import storage

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']
    
    # Validate input
    if not bucket_name or not file_name:
        raise ValueError("Bucket name and file name are required")
    
    # Set up ImageMagick command
    output_file = f"converted_{file_name}"
    convert_command = ['convert', os.path.join(bucket_name, file_name), output_file]
    
    try:
        # Run ImageMagick command
        subprocess.run(convert_command, check=True)
        
        # Upload converted image to storage
        client = storage.Client()
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(output_file)
        blob.upload_from_filename(output_file)
        
        os.remove(output_file)  # Clean up local file
        
        print(f"Image {file_name} converted and uploaded successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error converting image: {e}")